// CRA — process.env
const apiUrl = process.env.REACT_APP_API_URL;

// Vite equivalent — import.meta.env
const apiUrl = import.meta.env.VITE_API_URL;

// CRA — SVG as a React component (ReactComponent named export)
import { ReactComponent as Logo } from './logo.svg';

function Header() {
  return <Logo className="header-logo" />;
}

// Vite equivalent — install vite-plugin-svgr first:
import Logo from './logo.svg?react';

// config-overrides.js — modify webpack config at build time
module.exports = function override(config, env) {
  // add a webpack plugin, loader, or alias here
  config.resolve.alias['@'] = path.resolve(__dirname, 'src');
  return config;
};

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
export default defineConfig({ plugins: [react()] });

// src/App.test.tsx — what CRA generates by default
import { render, screen } from '@testing-library/react';
import App from './App';

test('renders learn react link', () => {
  render(<App />);
  const linkElement = screen.getByText(/learn react/i);
  expect(linkElement).toBeInTheDocument();
});

// This import applies ALL rules in Button.css globally:
import './Button.css';

// To scope rules, use the .module.css convention instead:
import styles from './Button.module.css';

import logo from './logo.png';
// Returns the public URL string — webpack copies the file to build/ with a hash
function Header() {
  return <img src={logo} alt="logo" />;
}

// Without baseUrl:
import Button from '../../components/Button';

// With baseUrl: "src"
import Button from 'components/Button';

import * as serviceWorkerRegistration from './serviceWorkerRegistration';
// Change to .register() to enable offline caching:
serviceWorkerRegistration.unregister();

import { lazy, Suspense } from 'react';

const About = lazy(() => import('./pages/About'));

function App() {
  return (
    <Suspense fallback={<p>Loading…</p>}>
      <Routes>
        <Route path="/about" element={<About />} />
      </Routes>
    </Suspense>
  );
}

// config-overrides.js
const path = require('path');

module.exports = function override(config) {
  // Add a module alias so @components resolves to src/components
  config.resolve.alias = {
    ...config.resolve.alias,
    '@components': path.resolve(__dirname, 'src/components'),
  };
  return config;
};

// config-overrides.js — add a second HTML entry (requires HtmlWebpackPlugin)
const HtmlWebpackPlugin = require('html-webpack-plugin');
const path = require('path');

module.exports = function override(config) {
  // Add a second page entry
  config.entry = {
    main:    './src/index.tsx',
    landing: './src/landing/index.tsx',
  };
  config.plugins.push(
    new HtmlWebpackPlugin({
      template: './public/landing.html',
      filename: 'landing.html',
      chunks: ['landing'],
    })
  );
  return config;
};
